namespace sv_bcb6d32872134f79b1622dfb055dbacd.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

namespace sv_bcb6d32872134f79b1622dfb055dbacd.Services;

/// <summary>
/// In-memory implementation of ISettingsService for development/demo purposes.
/// </summary>
public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new("Jane Doe", "jane@example.com", "https://i.pravatar.cc/150?u=jane", "Software developer and open-source enthusiast.");
    private NotificationPrefs _notificationPrefs = new(true, true, false, new List<string> { "marketing", "announcements" });
    private SecuritySettings _security = new(false, DateTime.UtcNow.AddDays(-45), new List<ActiveSession>
    {
        new("session-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("session-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
        new("session-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-3)),
    });
    private AppearanceSettings _appearance = new("System", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_notificationPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updated = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updated };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard d-flex">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar border-end p-3">
        <h5 class="mb-3">Settings</h5>
        <ul class="nav nav-pills flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link text-start w-100 @(section == _activeSection ? "active" : "")"
                            @onclick="() => _activeSection = section">
                        <span class="me-2">@GetIcon(section)</span>@section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content Area -->
    <main class="settings-content flex-grow-1 p-4">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private readonly string[] _sections = { "Profile", "Notifications", "Security", "Appearance" };
    private string _activeSection = "Profile";

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => ""
    };
}

.settings-dashboard {
    min-height: 80vh;
}

.settings-sidebar {
    min-width: 220px;
    max-width: 250px;
    background-color: var(--bs-light);
}

.settings-sidebar .nav-link {
    border-radius: 0.375rem;
    color: var(--bs-body-color);
    padding: 0.6rem 1rem;
    margin-bottom: 0.25rem;
}

.settings-sidebar .nav-link:hover:not(.active) {
    background-color: rgba(0, 0, 0, 0.05);
}

.settings-content {
    max-width: 800px;
}

@using sv_bcb6d32872134f79b1622dfb055dbacd.Services
@inject ISettingsService SettingsService

<h3 class="mb-4">Profile</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <!-- Toast Message -->
    @if (!string.IsNullOrEmpty(_toastMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <!-- Avatar Preview -->
    <div class="mb-4 d-flex align-items-center gap-3">
        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80" />
        <div>
            <label class="form-label mb-1">Avatar URL</label>
            <input type="url" class="form-control" style="max-width:400px" @bind="_avatarUrl" />
        </div>
    </div>

    <!-- Editable Fields -->
    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" style="max-width:400px" @bind="_displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" style="max-width:400px" @bind="_email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" style="max-width:400px" @bind="_bio"></textarea>
    </div>

    <!-- Action Buttons -->
    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Last saved state for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _toastMessage = "Profile saved successfully!";
        _saving = false;
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _toastMessage = null;
    }
}

@using sv_bcb6d32872134f79b1622dfb055dbacd.Services
@inject ISettingsService SettingsService

<h3 class="mb-4">Notifications</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    @if (!string.IsNullOrEmpty(_toastMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <!-- Toggle Switches -->
    <div class="mb-4">
        <h5>Preferences</h5>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <!-- Muted Channels -->
    <div class="mb-4">
        <h5>Muted Channels</h5>
        <p class="text-muted small">Check channels you want to mute.</p>

        @foreach (var channel in _allChannels)
        {
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @(_saving ? "Saving..." : "Save Preferences")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    // Available channels for demonstration
    private readonly string[] _allChannels = { "general", "marketing", "engineering", "announcements", "random", "support" };

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _toastMessage = "Notification preferences saved!";
        _saving = false;
    }
}

