                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> (@_sessionToRevoke.Location)?</p>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke">Revoke Session</button>
                    </div>
                </div>
            </div>
        </div>
