@code {
    private bool _loading = true;
    private string? _toastMessage;
    private string _toastClass = "alert-success";

    // Password fields
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _updatingPassword;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "session-1";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            _toastMessage = "Passwords do not match or are empty.";
            _toastClass = "alert-danger";
            return;
        }

        _updatingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _lastPasswordChange = DateTime.UtcNow;
        _toastMessage = "Password updated successfully!";
        _toastClass = "alert-success";
        _updatingPassword = false;
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _toastMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _toastClass = "alert-success";
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

