@using sv_bcb6d32872134f79b1622dfb055dbacd.Services
@inject ISettingsService SettingsService

<h3 class="mb-4">Security</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    @if (!string.IsNullOrEmpty(_toastMessage))
    {
        <div class="alert @_toastClass alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <!-- Change Password Expandable Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <strong>Change Password</strong>
            <span>@(_passwordExpanded ? "▲" : "▼")</span>
        </div>
        @if (_passwordExpanded)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" style="max-width:350px" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" style="max-width:350px" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" style="max-width:350px" @bind="_confirmPassword" />
                </div>
                <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_updatingPassword">
                    @(_updatingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <strong>Two-Factor Authentication</strong>
                <br />
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary") mt-1">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" style="transform: scale(1.3);" />
            </div>
        </div>
    </div>

    <!-- Last Password Change -->
    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <!-- Active Sessions -->
    <h5 class="mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (session.Id != _currentSessionId)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-info">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5)">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Confirm Session Revocation</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> (@_sessionToRevoke.Location)?</p>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke">Revoke Session</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private string? _toastMessage;
    private string _toastClass = "alert-success";

    // Password fields
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _updatingPassword;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "session-1";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            _toastMessage = "Passwords do not match or are empty.";
            _toastClass = "alert-danger";
            return;
        }

        _updatingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _lastPasswordChange = DateTime.UtcNow;
        _toastMessage = "Password updated successfully!";
        _toastClass = "alert-success";
        _updatingPassword = false;
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _toastMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _toastClass = "alert-success";
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

