toolArgs.file_text:
@using sv_bcb6d32872134f79b1622dfb055dbacd.Services
@inject ISettingsService SettingsService

<h3 class="mb-4">Appearance</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    @if (!string.IsNullOrEmpty(_toastMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <!-- Theme Selector -->
    <div class="mb-4">
        <h5>Theme</h5>
        @foreach (var theme in _themes)
        {
            <div class="form-check">
                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                       value="@theme" checked="@(_theme == theme)"
                       @onchange="() => _theme = theme" />
                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
            </div>
        }
    </div>

    <!-- Font Size Selector -->
    <div class="mb-4">
        <h5>Font Size</h5>
        @foreach (var size in _fontSizes)
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                       value="@size" checked="@(_fontSize == size)"
                       @onchange="() => _fontSize = size" />
                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
            </div>
        }
    </div>

    <!-- Language Dropdown -->
    <div class="mb-4">
        <h5>Language</h5>
        <select class="form-select" style="max-width:250px" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <!-- Compact Mode Toggle -->
    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="mb-4">
        <h5>Preview</h5>
        <div class="border rounded p-3" style="@GetPreviewStyle()">
            <h6>Sample Heading</h6>
            <p class="mb-1">This is how your content will look with the selected settings.</p>
            <button class="btn btn-sm btn-primary">Sample Button</button>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
        @(_saving ? "Saving..." : "Save")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = { "Light", "Dark", "System" };
    private readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewStyle()
    {
        var bg = _theme switch
        {
            "Dark" => "background-color: #1e1e1e; color: #e0e0e0;",
            "Light" => "background-color: #ffffff; color: #212529;",
            _ => "background-color: #f8f9fa; color: #212529;"
        };

        var fs = _fontSize switch
        {
            "Small" => "font-size: 0.85rem;",
            "Large" => "font-size: 1.15rem;",
            _ => "font-size: 1rem;"
        };

        var padding = _compactMode ? "padding: 0.5rem;" : "";

        return $"{bg} {fs} {padding}";
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _toastMessage = "Appearance settings saved!";
        _saving = false;
    }
}

